import React, { useEffect, useState } from 'react';
import { isAdmin } from './utils/auth';

function AdminDashboard() {
  const [users, setUsers] = useState([]);
  const [posts, setPosts] = useState([]);
  const [message, setMessage] = useState('');

  useEffect(() => {
    if (!isAdmin()) {
      window.location.href = '/';
      return;
    }
    // Fetch all users
    fetch('http://localhost:5003/api/admin/users', {
      headers: { Authorization: `Bearer ${localStorage.getItem('token')}` }
    })
      .then(res => res.json())
      .then(data => setUsers(data))
      .catch(err => console.error(err));

    // Fetch all posts
    fetch('http://localhost:5003/api/admin/posts', {
      headers: { Authorization: `Bearer ${localStorage.getItem('token')}` }
    })
      .then(res => res.json())
      .then(data => setPosts(data))
      .catch(err => console.error(err));
  }, []);

  const deletePost = (postId) => {
    fetch(`http://localhost:5003/api/admin/posts/${postId}`, {
      method: 'DELETE',
      headers: { Authorization: `Bearer ${localStorage.getItem('token')}` }
    })
      .then(() => setPosts(posts.filter(p => p._id !== postId)))
      .catch(err => setMessage('Delete failed'));
  };

  return (
    <div style={{ padding: '20px' }}>
      <h1>Admin Dashboard</h1>
      <h2>Users</h2>
      <ul>
        {users.map(u => <li key={u._id}>{u.name} - {u.email} - {u.role}</li>)}
      </ul>
      <h2>All Posts</h2>
      {posts.map(p => (
        <div key={p._id} style={{ border: '1px solid #ccc', margin: '10px', padding: '10px' }}>
          <h3>{p.title}</h3>
          <p>{p.content.substring(0, 100)}</p>
          <button onClick={() => deletePost(p._id)} style={{ background: 'red', color: 'white' }}>Delete</button>
        </div>
      ))}
      <p>{message}</p>
    </div>
  );
}

export default AdminDashboard;
